<script>
  import { Carousel, Slide } from 'vue-carousel';

  export default {
    data() {
      return {
        menuActive: false,
        articleActive: false,
        datesActive: false,
        name: null,
        email: null,
        text: null,
        dataSlide: 1,
        dataAllSlides: null

      }
    },
    computed: {
      menuClasses: function(){
        return {
          active: this.menuActive,
          openArticle: this.articleActive,
          openDates: this.datesActive
        };
      }
    },
    methods: {
      toggleArticle: function(){
        this.articleActive = !this.articleActive
        document.body.classList.toggle('fixed')

      },

      toggleDate: function(){
        this.datesActive = !this.datesActive
        document.body.classList.toggle('fixed')
      
      },

      toggleMenu: function(){
        this.menuActive = !this.menuActive
        document.body.classList.toggle('fixed')
      },

      handleSlideClick: function(dataset) {
        dataset++
        this.dataSlide = dataset
      },

      checkForm: function (e) {
        const currentForm = e.currentTarget
        const name = currentForm.querySelector('.form__name')
        const email = currentForm.querySelector('.form__email')
        const text = currentForm.querySelector('.form__text')

        if (!this.name) {
          this.addClassToInvalid(name)
        } else {
          this.removeClassToInvalid(name)
        }

         if (!this.email || !this.validEmail(this.email)) {
          this.addClassToInvalid(email)
          this.email = null
        } else {
          this.removeClassToInvalid(email)
        }

         if (!this.text) {
          this.addClassToInvalid(text)
        } else {
          this.removeClassToInvalid(text)
        }

        if(this.name) {

        }

        if (this.name && this.email && this.text) {
          return true
        }
  
        e.preventDefault();
      },
      validEmail: function (email) {
        var re = /^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
        return re.test(email);
      },

      addClassToInvalid: elem => elem.classList.add('invalid'),
      removeClassToInvalid: elem => elem.classList.remove('invalid'),

      handleRemoveInvalid: function (e) {

        if (e.currentTarget.classList.contains('invalid')) {
          if (e.currentTarget.classList.contains('form__name')) {
            this.name = null
          }

          // if (e.currentTarget.classList.contains('form__email')) {
          //   this.email = null
          // }

          if (e.currentTarget.classList.contains('form__text')) {
            this.text = null
          }
          
          e.currentTarget.classList.remove('invalid')
        }
      }
    },
    components: {
      Carousel,
      Slide,
    },

    mounted() {
      this.dataAllSlides = document.querySelector('.article__slider').querySelectorAll('.slide__item').length
    }
  }
</script>

