      font-size: 18px;
    
  


//ARTICLE
.article__container
  padding: 100px 70px 70px 70px

.article__body
  columns: 2
  column-gap: 4%
  margin-bottom: 50px
  padding-top: 50px
  
.article__title
  font-weight: bold
  text-transform: uppercase
  font-size: 50px
  margin-bottom: 15px

.article__subtitle
  font-size: 20px
  font-weight: bold
  text-transform: uppercase
  padding-bottom: 15px
  border-bottom: 1px solid #bbbbbb
  margin-bottom: 45px



.related__articles
  padding: 40px 70px 100px 70px
  background-color: #eeeeee
  width: 100%

  .slide__title
    transition: all .1s ease
    @media (min-width: 770px) 
      &:hover
        color: $red

  span
    display: block
    text-transform: uppercase
    font-size: 20px
    color: $red
    font-weight: bold
    margin-bottom: 15px

@media (max-width: 1199px)
  .article__body
    columns: 1

  .article__text
    margin-bottom: 20px

  .article__slider
    margin: 0 auto 40px auto

  .slider__pagination
    text-align: center

@media (max-width: 769px)
  .article__title
    font-size: 30px

  .related__articles
    padding: 15px 15px 100px 15px

  .article__container
    padding: 100px 15px 100px 15px

//DATES
.dates
  width: 100%
  margin-top: 40px
  border-top: 1px solid #eeeeee
  > *
    color: #717171
    font-size: 15px
    font-weight: bold
    text-transform: uppercase

.dates__item
  display: flex
  justify-content: space-between
  width: 100% 
  align-items: center
  padding: 30px 0
  border-bottom: 1px solid #eeeeee
  .date:before
    margin-bottom: -2px
  > *
    width: 25%
    text-align: left

  @media (max-width: 769px)
    flex-direction: column
    align-items: flex-start
    justify-content: flex-start
    > *
      text-align: left
      width: 100%
      margin-bottom: 10px


  .dates__info
    max-width: 100px


.dates__title
  font-size: 50px
  font-weight: bold
  text-transform: uppercase
  max-width: 550px
  line-height: 1.1
  margin-bottom: 8px

.dates__subtitle
  font-size: 20px
  text-transform: uppercase
  max-width: 550px

@media (max-width: 769px)

  .dates__title
    margin-top: 30px
    font-size: 30px

//helpers
.modal__helpers
  position: absolute
  right: -100px
  top: 67px
  z-index: 100
  > *
    height: 100px
    width: 100px
    display: block !important

.share
  background-color: #000
  color: #fff
  font-size: 30px
  text-align: center
  padding-top: 40px
  transition: all .25s ease

  @media (min-width: 770px) 
    &:hover
      color: $red
  
.modal__close
  background-color: #e5eaee
  position: relative
  cursor: pointer
  &:before,
  &:after
    content: ''
    left: 30px
    position: absolute
    display: block
    height: 7px
    width: 35px
    background-color: #000000
    transition: all .25s ease
    left: 50%
    top: 50%
  &:after
    transform: translateX(-50%) translateY(-50%) rotate(-45deg)
  &:before
    transform: translateX(-50%) translateY(-50%) rotate(45deg)

  @media (min-width: 770px) 
    &:hover,
      &:before,
      &:after
        background-color: $red


@media (max-width: 1399px)
  .modal__helpers
    right: 0
    top: 53px
    display: flex
    flex-direction: row-reverse
    height: 50px


    > *
      height: 100%
      width: 60px
  // .modal__close
  //   &:after
  //     top: 23px
  //   &:before
  //     bottom: 20px

  .share
    padding-top: 10px
      

@media (max-width: 469px)
  .modal__helpers
    width: 100%
    > *
      width: 25%

  .modal__close
    &:before,
    &:after
      left: 50%

    &:after
      transform: translateX(-50%) rotate(-45deg)
    &:before
      transform: translateX(-50%) rotate(45deg)


.modal__wrapper
  position: fixed
  height: 100vh
  width: 100vw
  top: 0
  left: 0
  right: 0
  z-index: 300
  pointer-events: none
  &.openArticle
    pointer-events: all
    .modal__overlay
      opacity: 1
      pointer-events: all
    .modal__article
      top: 0

  &.openDates
    pointer-events: all
    .modal__overlay
      opacity: 1
      pointer-events: all
    .modal__dates
      top: 0


.modal__overlay
  position: fixed
  width: 100vw
  height: 100vh
  left: 0
  right: 0
  top: 0
  bottom: 0
  background-color: rgba(0,0,0,.5)
  z-index: 300
  opacity: 0
  pointer-events: none
  transition: all .3s ease


.article__scroll
  overflow: scroll
  height: 100vh
.modal
  background-color: #fff
  position: absolute
  max-width: 1200px
  width: 100%
  margin: 0 auto
  z-index: 302
  top: -120%
  transition: all .4s ease
  left: 50%
  transform: translateX(-50%)

  .line
    margin: 0
    margin-bottom: 15px

  .date
    color: #717171
    font-size: 15px
    font-weight: bold
    text-transform: uppercase

    &:before
      content: ''
      display: inline-block
      vertical-align: bottom
      margin-right: 10px
      width: 28px
      height: 28px
      background: url('./assets/Calendar.svg') no-repeat center

.modal__header
  display: flex
  justify-content: flex-end
  background-color: #fff
.modal__logo
  // width: calc(100% + 100px)
  // right: 0
  width: 35%
  right: -100px
  position: relative
  min-width: 220px
  background-color: $red
  padding: 10px 2vw
  text-align: right
  z-index: 100
  svg
    max-width: 220px
    max-height: 43px //ie fix

@media (max-width: 1399px)
  .modal__logo
    right: 0
    width: 360px
    padding: 3px 10px

@media (max-width: 469px)
  .modal__logo
    width: 100%

.news
  display: flex
  flex-direction: column
  position: relative
  margin-top: -120px
  @media (max-width: 769px)
    margin-top: 0

.news__line
  display: flex
  justify-content: space-between
  flex-wrap: wrap
  &:first-of-type
    .news__link
      padding-top: 150px

  @media (max-width: 998px)
    flex-direction: column

  @media (max-width: 769px)
    &:first-of-type
      .news__link
        padding-top: 15px




.news__column
  width: 50%
  display: flex
  justify-content: space-between
  flex-wrap: wrap
  @media (max-width: 998px)
    width: 100%

.news__link
  display: flex
  flex-direction: column
  justify-content: flex-end
  width: 50%
  padding: 28px

  @media (max-width: 769px)
    padding: 15px

  @media (max-width: 499px)
    width: 100%
    align-items: center


  h2
    color: $red
    font-size: 20px
    font-weight: bold
    text-transform: uppercase
    margin: 8px 0
    max-width: 295px
    text-overflow: ellipsis
    overflow: hidden
    transition: all .2s ease
    @media (min-width: 770px) 
      &:hover
        color: darken($red, 13%);
  p
    max-width: 295px
    max-height: 70px
    text-overflow: ellipsis
    overflow: hidden

  .date
    color: #717171
    font-size: 15px
    font-weight: bold
    text-transform: uppercase
    &:before
      content: ''
      display: inline-block
      margin-right: 10px
      width: 28px
      height: 28px
      background: url('./assets/Calendar.svg') no-repeat center

  &_large
    position: relative
    width: 100%
    padding: 40px
    @media (max-width: 769px)
      padding: 15px
    h2
      font-size: 30px
      margin-bottom: 3px
      max-width: 620px
      text-overflow: ellipsis
      overflow: hidden

    h4
      font-size: 20px
      text-transform: uppercase
      margin-bottom: 8px

    .date
      font-size: 50px;
      color: #000000
      &:before
        display: none

  &_bright
    background-color: #e5eaee

  &_dark
    background-color: #000
    p
      color: white


.news__link_background-1
  background: url('./assets/big_news_1.png') no-repeat
  background-color: #e5eaee
  background-size: cover
  @media (max-width: 998px)
    padding-top: 40px!important

.news__link_background-2
  background: url('./assets/big_news_2.png') no-repeat
  background-color: #e5eaee
  background-size: cover

.news__photo
  position: relative
  width: 50%
  padding: 0
  overflow: hidden
  &:after
    content: ''
    position: absolute
    left: 0
    top: 0
    width: 100%
    height: 100%
    background-color: #000
    z-index: 2
    opacity: .3
    transition: all .25s ease

  @media (min-width: 770px) 
    &:hover
      img
        transform: scale(1.2)
      &:after
        opacity: 0

  &_large
    width: 100%

  img
    object-fit: cover
    transition: all 5000ms cubic-bezier(0.000, 1.255, 0.105, 0.905)
    height: 100%
    width: 100%

  @media (max-width: 998px)
    &:after
      display: none




// MORE

.news__more-background
  position: absolute
  width: 100%
  height: 100%
  &:after
    content: ''
    position: absolute
    left: 0
    top: 0
    width: 100%
    height: 100%
    background-color: #000
    z-index: 2
    opacity: .7
    transition: all .25s ease

.news__triangle
  background-color: #000000
  width: 100%
  height: 100%
  z-index: 2
  position: absolute
  -webkit-clip-path: polygon(0 0, 100% 0, 100% 0, 0 100%)
  clip-path: polygon(0 0, 100% 0, 100% 0, 0 100%)
  transition: all 5000ms cubic-bezier(0.000, 1.255, 0.105, 0.905)

  &_reverse
    -webkit-clip-path: polygon(0 0, 0 0, 100% 100%, 100% 0)
    clip-path: polygon(0 0, 0 0, 100% 100%, 100% 0)

.news__more-photo
  background: url('./assets/news_plus.png') no-repeat center
  background-size: cover
  position: absolute
  z-index: 1
  width: 100%
  height: 100%
  right: 0
  &-2
    background: url('./assets/dates-more.png') no-repeat center
.news__more-content
  display: flex
  flex-direction: column
  justify-content: center
  align-items: center
  position: relative
  width: 100%
  height: 100%
  z-index: 3
  color: #fff
  text-transform: uppercase
  text-align: center

  h2
    margin-top: 15px


.news__more
  padding: 0
  min-height: 280px
  @media (min-width: 770px) 
    &:hover
      .news__more-background:after
        opacity: .2
      .news__triangle
        -webkit-clip-path: polygon(0 0, 100% 0, 100% 66%, 0 42%)
        clip-path: polygon(0 0, 100% 0, 100% 66%, 0 42%)
      .news__triangle_reverse
        -webkit-clip-path: polygon(0 0, 0 45%, 100% 60%, 100% 0)
        clip-path: polygon(0 0, 0 45%, 100% 60%, 100% 0)

.quote
  position: relative
  z-index: 4
  margin-top: 80px
  padding: 10px 40px 200px 40px
  background: url('./assets/timeline.png') no-repeat bottom
  @media (max-width: 769px)
    padding: 10px 15px 200px 15px
.quote__inner
  margin: 0 auto
  max-width: 1048px

.quote__title,
.quote__subtitle
  text-align: center
  text-transform: uppercase
  margin-bottom: 20px

.quote__title
  font-size: 50px
  @media (max-width: 769px)
    font-size: 30px

.quote__subtitle
  font-size: 20px


.quote__caption
  margin-top: 50px
  color: #6b6b6b
  display: flex
  justify-content: space-between
  line-height: 1.5
  font-weight: 100
  margin-bottom: 100px
  @media (max-width: 998px)
    flex-direction: column
    justify-content: center
    align-items: center

.quote__caption__column
  width: 48%
  @media (max-width: 998px)
    margin-bottom: 30px
    width: 100%


.line
  display: block
  width: 100%
  margin: 0 auto
  max-width: 390px
  background-color: #bbbbbb
  height: 1px
  &_white
    background-color: #fff

.article__slider
  display: inline-block //webkit
  max-width: 500px
  max-height: 350px
  margin-bottom: 40px
  @media (max-width: 1199px)
    display: block //webkit

  .VueCarousel-wrapper
    z-index: 1
  .VueCarousel-navigation-button
    width: 50px
    height: 50px
    background-color: rgba(0,0,0,.8) !important
    outline: none!important
    z-index: 3

  .VueCarousel-navigation-next
    right: 50px !important
  .VueCarousel-navigation-prev
    left: 50px !important

  .VueCarousel-navigation-next:after,
  .VueCarousel-navigation-prev:after
    font-family: 'Font Awesome 5 Free'
    content: '\f105'
    font-size: 43px
    color: #ffffff
    font-weight: bold
    position: absolute
    left: 0
    top: 0
    width: 100%
    height: 100%
    display: block


  .VueCarousel-navigation-prev:after
    content: '\f104'



.slider__pagination
  margin-top: 5px
  text-align: right
  font-weight: bold

.slide__item img
  height: 350px
  width: 100%
  object-fit: cover


.related__slider
  margin: 0 -15px

  .VueCarousel-pagination
    display: none

  .slide__item
    padding: 0 15px
    width: 250px
    img
      margin-bottom: 15px
      width: 100%
      height: 150px
      object-fit: cover

  .slide__title
    font-size: 20px
    display: block
    text-transform: uppercase
    margin-bottom: 10px
    font-weight: bold

  .VueCarousel-navigation-button
    width: 50px
    height: 50px
    outline: none !important

  .VueCarousel-navigation-next
    right: 6px !important

  @media (max-width: 769px)
    .VueCarousel-navigation-button
      display: none
    .VueCarousel-pagination
      display: block

    .VueCarousel-dot
      background-color: rgb(153, 153, 153)!important

    .VueCarousel-dot--active
      background-color: #000000!important

    


  .VueCarousel-navigation-next:after,
  .VueCarousel-navigation-prev:after
    font-family: 'Font Awesome 5 Free'
    content: '\f105'
    font-size: 43px
    color: #000000
    font-weight: bold
    position: absolute
    left: 0
    top: 0
    width: 100%
    height: 100%
    display: block

  .VueCarousel-navigation-prev:after
    content: '\f104'


.team
  position: relative
  z-index: 3
  background-color: #000
  padding-top: 100px

  @media (max-width: 769px)
    padding-top: 0

  &:after
    content: ''
    display: block
    width: 100%
    height: 160px
    position: absolute
    top: -160px
    background: url('./assets/Rectangle1.svg') no-repeat center

.team__caption
  padding: 15px
.team__title,
.team__subtitle
  color: #ffffff
  text-transform: uppercase
  text-align: center
  margin-bottom: 20px

.team__title
  font-size: 50px
  @media (max-width: 769px)
    font-size: 30px

.team__subtitle
  font-size: 20px

.team__members
  display: flex
  margin-top: 40px
  justify-content: center
  flex-wrap: wrap



.team__item__caption
  position: absolute
  display: flex
  flex-direction: column
  justify-content: flex-end
  padding: 30px
  width: 100%
  height: 100%
  top: 0
  left: 20%
  background-color: #e5eaee
  color: #000000
  z-index: 1
  opacity: 0
  pointer-events: none
  transition: all .25s ease

.team__item
  position: relative
  height: 280px
  width: 280px
  background-color: black

  img
    filter: grayscale(100%)
    transition: all .25s ease

  &:hover
    img
      filter: grayscale(0%)

    .team__item__caption
      left: 100%
      opacity: 1
      // pointer-events: all

  // description logic
  @media (min-width: 1400px)
    &:nth-of-type(5n),
    &:last-child
      .team__item__caption
        left: auto
        right: 20%

      @media (min-width: 770px) 
        &:hover .team__item__caption
          right: 100%


  @media (min-width: 1120px) and (max-width: 1399px)
    &:nth-of-type(4n),
    &:last-child
      .team__item__caption
        left: auto
        right: 20%

      @media (min-width: 770px) 
        &:hover .team__item__caption
        right: 100%


  @media (min-width: 840px) and (max-width: 1119px)
    &:nth-of-type(3n),
    &:last-child
      .team__item__caption
        left: auto
        right: 20%

      @media (min-width: 770px) 
        &:hover .team__item__caption
          right: 100%

    


  @media (max-width: 839px)
    .team__item__caption
      background-color: rgba(229, 234, 238, .6)
      left: 0 !important
      right: 0 !important

    @media (min-width: 770px) 
      &:hover
        img
          filter: grayscale(100%)

    
.member__name
  text-transform: uppercase
  font-size: 20px
  

</style>



